import pika
import json
import time
import sys
from datetime import datetime
import threading


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_message(self, message):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        message_body = json.dumps({
            'task': message,
            'timestamp': datetime.now().isoformat(),
            'status': 'pending'
        })
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message_body,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f"[Publisher] Sent: {message}")
        
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_task(self, task_data):
        print(f"[Consumer] Processing task: {task_data['task']}")
        time.sleep(task_data['task'].count('.'))
        print(f"[Consumer] Task completed: {task_data['task']}")
        
    def callback(self, ch, method, properties, body):
        try:
            message = json.loads(body)
            print(f"[Consumer] Received: {message}")
            self.process_task(message)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"[Consumer] Error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        print(f"[Consumer] Waiting for messages on queue '{self.queue_name}'...")
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            print("\n[Consumer] Stopping...")
            self.channel.stop_consuming()
            
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


def run_publisher():
    publisher = RabbitMQPublisher()
    
    try:
        publisher.connect()
        
        tasks = [
            "Task 1: Simple task",
            "Task 2: Medium task..",
            "Task 3: Complex task....",
            "Task 4: Quick task",
            "Task 5: Long running task......",
        ]
        
        for task in tasks:
            publisher.publish_message(task)
            time.sleep(1)
            
        print("[Publisher] All tasks published")
        
    except Exception as e:
        print(f"[Publisher] Error: {e}")
    finally:
        publisher.close()


def run_consumer():
    consumer = RabbitMQConsumer()
    
    try:
        consumer.connect()
        consumer.start_consuming()
    except Exception as e:
        print(f"[Consumer] Error: {e}")
    finally:
        consumer.close()


def main():
    if len(sys.argv) < 2:
        print("Usage: python script.py [publisher|consumer]")
        sys.exit(1)
        
    mode = sys.argv[1].lower()
    
    if mode == 'publisher':
        run_publisher()
    elif mode == 'consumer':
        run_consumer()
    elif mode == 'both':
        consumer_thread = threading.Thread(target=run_consumer, daemon=True)
        consumer_thread.start()
        time.sleep(2)
        run_publisher()
        consumer_thread.join(timeout=30)
    else:
        print("Invalid mode. Use 'publisher', 'consumer', or 'both'")
        sys.exit(1)


if __name__ == '__main__':
    main()